  1→package com.yottastudios.ns.collabspace.workspace.controller;
  2→
  3→import com.yottastudios.ns.collabspace.control.check.PermissionChecker;
  4→import com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants;
  5→import com.yottastudios.ns.collabspace.core.support.ResponseData;
  6→import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
  7→import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
  8→import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
  9→import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
 10→import com.yottastudios.ns.collabspace.shared.context.SessionContext;
 11→import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
 12→import com.yottastudios.ns.collabspace.space.vo.SpaceVo;
 13→import com.yottastudios.ns.collabspace.workspace.enums.VersionSnapshotStatusEnum;
 14→import com.yottastudios.ns.collabspace.workspace.ro.*;
 15→import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeMigrationUpdateManager;
 16→import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeMigrationQueryManager;
 17→import com.yottastudios.ns.collabspace.workspace.vo.CopyFileVo;
 18→import com.yottastudios.ns.collabspace.workspace.vo.CopyVersionSnapshotVo;
 19→import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeMigrationTaskVo;
 20→import com.yottastudios.ns.collabspace.workspace.vo.VersionSnapshotVo;
 21→import io.swagger.v3.oas.annotations.Operation;
 22→import io.swagger.v3.oas.annotations.Parameter;
 23→import io.swagger.v3.oas.annotations.Parameters;
 24→import io.swagger.v3.oas.annotations.enums.ParameterIn;
 25→import io.swagger.v3.oas.annotations.media.Schema;
 26→import io.swagger.v3.oas.annotations.tags.Tag;
 27→import jakarta.annotation.Resource;
 28→import jakarta.validation.Valid;
 29→import lombok.extern.slf4j.Slf4j;
 30→import org.springframework.scheduling.annotation.Scheduled;
 31→import org.springframework.web.bind.annotation.PathVariable;
 32→import org.springframework.web.bind.annotation.RequestBody;
 33→import org.springframework.web.bind.annotation.RestController;
 34→
 35→import java.util.ArrayList;
 36→import java.util.Arrays;
 37→import java.util.List;
 38→
 39→@Slf4j
 40→@RestController
 41→@Tag(name = "Space Node Migration")
 42→@ApiResource(path = "/spaceNode/migration")
 43→public class SpaceNodeMigrationController {
 44→
 45→    @Resource
 46→    private SpaceNodeMigrationUpdateManager spaceNodeMigrationUpdateManager;
 47→
 48→    @Resource
 49→    private SpaceNodeMigrationQueryManager spaceNodeMigrationQueryManager;
 50→
 51→    @Resource
 52→    private PermissionChecker permissionChecker;
 53→
 54→    @PostResource(path = "/createMigrationTask", requiredSpaceAdmin = true)
 55→    @Parameters({
 56→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
 57→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
 58→    })
 59→    @Operation(summary = "Create migration task")
 60→    public ResponseData<String> createMigrationTask(@RequestBody @Valid MigrationTaskCreateRo ro) {
 61→        Long userId = SessionContext.getUserId();
 62→        String sourceSpaceId = SpaceHolder.get();
 63→        if (ro.getIsRemained() == null) {
 64→            // 默认保留
 65→            ro.setIsRemained(true);
 66→        }
 67→        String taskId = spaceNodeMigrationUpdateManager.createMigrationTask(
 68→                ro.getSpaceNodeIds(), 
 69→                ro.getTargetSpaceId(), 
 70→                sourceSpaceId, 
 71→                userId,
 72→                ro.getIsRemained()
 73→        );
 74→        return ResponseData.success(taskId);
 75→    }
 76→
 77→    @GetResource(path = "/task/{taskId}", requiredPermission = false)
 78→    @Operation(summary = "Get migration task info")
 79→    public ResponseData<SpaceNodeMigrationTaskVo> getMigrationTaskInfo(
 80→            @PathVariable("taskId") @Parameter(description = "Task ID", example = "spc123-spc456-1234567890") String taskId) {
 81→        SpaceNodeMigrationTaskVo taskInfo = spaceNodeMigrationQueryManager.getMigrationTaskInfo(taskId);
 82→        return ResponseData.success(taskInfo);
 83→    }
 84→    
 85→    @GetResource(path = "/managedSpaces", requiredPermission = false)
 86→    @Operation(summary = "Get user managed spaces for migration")
 87→    public ResponseData<List<SpaceVo>> listManagedSpaceForMigration() {
 88→        Long userId = SessionContext.getUserId();
 89→        List<SpaceVo> spaces = spaceNodeMigrationQueryManager.listManagedSpaceForMigration(userId);
 90→        return ResponseData.success(spaces);
 91→    }
 92→
 93→
 94→    @PostResource(path = "/copyFile")
 95→    @Parameters({
 96→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
 97→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
 98→    })
 99→    @Operation(summary = "Copy file")
100→    public ResponseData<List<CopyFileVo>> copyFile(@RequestBody @Valid CopyFileRo ro){
101→        Long userId = SessionContext.getUserId();
102→        String spaceId = SpaceHolder.get();
103→        permissionChecker.requireUser(userId).onNodes(ro.getSpaceNodeIds()).needRole(RoleConstants.SpaceNode.EDITOR);
104→        List<CopyFileVo> voList = spaceNodeMigrationUpdateManager.copyFile(ro.getSpaceNodeIds(), userId, spaceId, spaceId);
105→        return ResponseData.success(voList);
106→
107→    }
108→
109→    @PostResource(path = "/version/copy")
110→    @Parameters({
111→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
112→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
113→    })
114→    @Operation(summary = "Copy Version Snapshot")
115→    public ResponseData<CopyVersionSnapshotVo> copyVersionSnapshot(@RequestBody @Valid CopyVersionSnapshotRo ro){
116→        Long userId = SessionContext.getUserId();
117→        String spaceId = SpaceHolder.get();
118→        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.EDITOR);
119→        CopyVersionSnapshotVo vo = spaceNodeMigrationUpdateManager.copyVersionSnapshot(ro.getSpaceNodeId(), ro.getSnapshotName(),
120→                spaceId, spaceId ,userId, ro.getType());
121→        return ResponseData.success(vo);
122→
123→    }
124→
125→    // 列表
126→    @PostResource(path = "/version/list")
127→    @Operation(summary = "Get Version List")
128→    public ResponseData<List<VersionSnapshotVo>> listVersionSnapshot(@RequestBody @Valid VersionSnapshotRo ro){
129→        Long userId = SessionContext.getUserId();
130→        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.READER);
131→        List<VersionSnapshotVo> voList = spaceNodeMigrationQueryManager.listVersionSnapshot(ro.getSpaceNodeId(),ro.getStatus());
132→        return ResponseData.success(voList);
133→
134→    }
135→
136→    @PostResource(path = "/version/update")
137→    @Operation(summary = "update snapshot name")
138→    public ResponseData<VersionSnapshotVo> updateVersionSnapshot(@RequestBody @Valid UpdateSnapshotRo ro){
139→        Long userId = SessionContext.getUserId();
140→        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
141→        VersionSnapshotVo vo = spaceNodeMigrationUpdateManager.updateVersionSnapshot(ro.getId(), ro.getName());
142→        return ResponseData.success(vo);
143→    }
144→
145→
146→    @PostResource(path = "/version/delete")
147→    @Operation(summary = "delete snapshot")
148→    public ResponseData<Void> deleteVersionSnapshot(@RequestBody @Valid SnapshotRo ro){
149→        Long userId = SessionContext.getUserId();
150→        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
151→        spaceNodeMigrationUpdateManager.deleteVersionSnapshot(ro.getId());
152→        return ResponseData.success();
153→    }
154→
155→    @PostResource(path = "/version/recover")
156→    @Operation(summary = "recover snapshot")
157→    public ResponseData<Void> recoverVersionSnapshot(@RequestBody @Valid SnapshotRo ro){
158→        Long userId = SessionContext.getUserId();
159→        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
160→        spaceNodeMigrationUpdateManager.recoverVersionSnapshot(ro.getId());
161→        return ResponseData.success();
162→    }
163→
164→    @Operation(summary = "delete overtime snapshot")
165→    @Scheduled(cron = "0 0 10 * * ?")
166→    public void syncAnnouncement() {
167→        spaceNodeMigrationUpdateManager.deleteOverTimeSnapshot();
168→    }
169→
170→    @PostResource(path = "/copyShareFile", requiredPermission = false)
171→    @Operation(summary = "Copy Share file")
172→    public ResponseData<List<CopyFileVo>> copyShareFile(@RequestBody @Valid CopyShareFileRo ro){
173→        Long userId = SessionContext.getUserId();
174→        String targetSpaceId = ro.getTargetSpaceId();
175→        permissionChecker.requireUser(userId).onSpace(targetSpaceId).needAdmin();
176→        List<CopyFileVo> result = spaceNodeMigrationUpdateManager.copyShareFile(ro.getSpaceNodeIds(), userId, targetSpaceId, ro.getShareId());
177→        return ResponseData.success(result);
178→    }
179→}
